import React from "react";
import AppRouter from "./components/misc/router";
import { navPathConstants as navPaths } from "@lakefusion/utility-portal";
import { createBrowserHistory } from "history";

const App = () => {
  const history = createBrowserHistory();

  const routerArgs = {
    navPaths: navPaths,
  };

  return <AppRouter routerArgs={routerArgs} history={history} />;
};

export default App;
