import React from "react";
import { useHistory, useLocation } from "react-router-dom";
import { ScrollText, BookOpen, ArrowLeft } from "lucide-react";

interface TooltipProps {
  children: React.ReactNode;
  content: string;
  side?: "right" | "left" | "top" | "bottom";
}

const Tooltip: React.FC<TooltipProps> = ({ children, content, side = "right" }) => {
  const [isVisible, setIsVisible] = React.useState(false);

  return (
    <div
      className="relative inline-block w-full"
      onMouseEnter={() => setIsVisible(true)}
      onMouseLeave={() => setIsVisible(false)}
    >
      {children}
      {isVisible && (
        <div
          className={`absolute z-50 px-2 py-1 text-xs text-white bg-neutral-800 rounded shadow-lg whitespace-nowrap ${
            side === "right" ? "left-full ml-2 top-1/2 -translate-y-1/2" : ""
          }`}
        >
          {content}
        </div>
      )}
    </div>
  );
};

interface SidebarItem {
  label: string;
  icon: React.ComponentType<{ className?: string }>;
  path: string;
  section: string;
  iconColor: string;
  iconBgColor: string;
}

interface SidebarSection {
  label: string;
}

const sections: SidebarSection[] = [
  { label: "Self-Service Tools" },
  { label: "Navigation" },
];

const sidebarItems: SidebarItem[] = [
  {
    label: "Console Log Viewer",
    icon: ScrollText,
    path: "/selfservice/console",
    section: "Self-Service Tools",
    iconColor: "text-amber-400",
    iconBgColor: "bg-amber-400/20",
  },
  {
    label: "Documentation Hub",
    icon: BookOpen,
    path: "/selfservice/docs",
    section: "Self-Service Tools",
    iconColor: "text-sky-400",
    iconBgColor: "bg-sky-400/20",
  },
  {
    label: "Back to Main Portal",
    icon: ArrowLeft,
    path: "/",
    section: "Navigation",
    iconColor: "text-neutral-400",
    iconBgColor: "bg-neutral-400/20",
  },
];

interface SelfServiceSidebarProps {
  openSidebar?: boolean;
}

export const SelfServiceSidebar: React.FC<SelfServiceSidebarProps> = ({ openSidebar = true }) => {
  const history = useHistory();
  const location = useLocation();

  const handleNavigation = (path: string) => {
    if (path === "/") {
      window.location.href = path;
    } else {
      history.push(path);
    }
  };

  return (
    <div
      className={`Sidebar h-full bg-gradient-to-b from-secondary to-secondary-foreground flex flex-col items-center ${
        openSidebar ? "w-60" : "w-14"
      } pt-4 transition-all duration-300 shrink-0`}
    >
      {sections.map((section) => (
        <div key={section.label} className="w-full">
          {openSidebar && (
            <div className="section-label mb-4 text-xs items-center flex mx-5 text-neutral-300 font-['Inter'] capitalize tracking-wide">
              {section.label}
            </div>
          )}
          <div className="space-y-2">
            {sidebarItems
              .filter((item) => item.section === section.label)
              .map((item) => {
                const IconComponent = item.icon;
                const isActive = location.pathname === item.path ||
                  (item.path !== "/" && location.pathname.startsWith(item.path));

                const buttonContent = (
                  <button
                    className={`${openSidebar ? "ml-2 mr-3 px-1.5" : "ml-1.5 mr-1.5 px-1.5"} py-1.5 h-9 ${openSidebar ? "w-full" : "w-10"} justify-start flex items-center ${openSidebar ? "gap-2.5" : "justify-center"}
                      ${
                        isActive
                          ? "text-neutral-50"
                          : "text-neutral-300 hover:bg-neutral-700/50 hover:text-neutral-50"
                      }
                      rounded-lg transition-all duration-200`}
                    onClick={() => handleNavigation(item.path)}
                  >
                    <div
                      className={`w-7 h-7 rounded-lg flex items-center justify-center shrink-0 ${
                        isActive ? item.iconBgColor : ""
                      }`}
                    >
                      <IconComponent className={`h-5 w-5 ${item.iconColor}`} />
                    </div>
                    {openSidebar && (
                      <span className="text-sm font-normal font-['Inter'] leading-normal truncate">
                        {item.label}
                      </span>
                    )}
                  </button>
                );

                return (
                  <div
                    key={item.label}
                    className="w-full flex items-center text-primary-foreground"
                  >
                    {isActive ? (
                      <div className="w-1 h-9 bg-gradient-to-b from-red-800 to-red-50 rounded-tr rounded-br" />
                    ) : (
                      <div className="w-1 h-9" />
                    )}
                    {!openSidebar ? (
                      <Tooltip content={item.label} side="right">
                        {buttonContent}
                      </Tooltip>
                    ) : (
                      buttonContent
                    )}
                  </div>
                );
              })}
          </div>
          <hr className="my-4 mx-4 border-neutral-700" />
        </div>
      ))}
    </div>
  );
};

export default SelfServiceSidebar;
