import React, { lazy } from "react";
import { Route, Router, Switch, Redirect, useParams } from "react-router-dom";
import { createBrowserHistory } from "history";
import {
  RevampedPrivateRoute as PrivateRoute,
  PublicRoute,
  NotFound,
} from "@lakefusion/utility-portal";
import { SelfServiceSidebar } from "../sidebar/SelfServiceSidebar";

const ConsoleLogViewer = lazy(() => import("../console/ConsoleLogViewer"));
const DocumentationHub = lazy(() => import("../docs/DocumentationHub"));
const DocViewer = lazy(() => import("../docs/DocViewer"));

// Wrapper to extract route params for DocViewer
interface DocRouteParams {
  version?: string;
  0?: string; // wildcard path
}

const DocViewerWrapper: React.FC = () => {
  const params = useParams() as DocRouteParams;
  const version = params.version;
  // Access the wildcard path - in react-router v5, it's stored as index 0
  const path = params[0];
  return <DocViewer version={version} path={path} />;
};

interface RouteConfig {
  path: string;
  component: React.ComponentType<any>;
  isPrivate: boolean;
  exact: boolean;
  showConsoleOption: boolean;
  showSidebar: boolean;
}

const AppRouter = (props: { routerArgs: any; history: any }) => {
  const routerArgs = props.routerArgs || {};
  const history = props.history || createBrowserHistory();

  // Custom sidebar element to pass to PrivateRoute
  const customSidebar = <SelfServiceSidebar openSidebar={true} />;

  const routes: RouteConfig[] = [
    {
      path: "/selfservice",
      component: () => <Redirect to="/selfservice/console" />,
      isPrivate: true,
      exact: true,
      showConsoleOption: false,
      showSidebar: true,
    },
    {
      path: "/selfservice/console",
      component: ConsoleLogViewer,
      isPrivate: true,
      exact: true,
      showConsoleOption: false,
      showSidebar: true,
    },
    {
      path: "/selfservice/docs",
      component: DocumentationHub,
      isPrivate: true,
      exact: true,
      showConsoleOption: false,
      showSidebar: true,
    },
    {
      path: "/selfservice/docs/:version/*",
      component: DocViewerWrapper,
      isPrivate: true,
      exact: false,
      showConsoleOption: false,
      showSidebar: true,
    },
  ];

  const routeComponents = routes.map((item, index) => {
    const routeProps = {
      path: item.path || "",
      exact: item.exact || false,
      component: item.component || "",
      routerArgs: routerArgs,
      showConsoleOption: "showConsoleOption" in item ? item.showConsoleOption : true,
      showSidebar: "showSidebar" in item ? item.showSidebar : true,
      customSidebar: item.showSidebar ? customSidebar : undefined,
    };

    const RouteComponent = item.isPrivate ? PrivateRoute : PublicRoute;
    return (
      <Route {...routeProps} key={index}>
        <RouteComponent {...routeProps} />
      </Route>
    );
  });

  return (
    <Router history={history}>
      <Switch>
        {routeComponents}
        <Route key={"notfound"}>
          <PublicRoute routerArgs={routerArgs} component={NotFound} exact />
        </Route>
      </Switch>
    </Router>
  );
};

export default AppRouter;
